\n\t[Direction] [nvarchar](10) NULL,\r\n\t[TruckNumber] [nvarchar](50) NULL,\r\n\t[HasPhysicalTicket] [bit] NULL,\r\n\t[PhysicalTicketNumber] [nvarchar](100) NULL,\r\n\t[SignedBy] [nvarchar](100) NULL,\r\n\t[CreatedAt] [datetime] NULL,\r\nPRIMARY KEY CLUSTERED \r\n(\r\n\t[TicketID] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY],\r\n CONSTRAINT [UQ_FormTicketNumber] UNIQUE NONCLUSTERED \r\n(\r\n\t[FormTicketNumber] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Fact_SiteTickets' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [dbo].[Stage_SiteTickets]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Stage_SiteTickets' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  Table [dbo].[Stage_SiteTickets]    Script Date: 3/17/2026 1:39:56 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE TABLE [dbo].[Stage_SiteTickets](\r\n\t[StageID] [int] IDENTITY(1,1) NOT NULL,\r\n\t[GoFormz_ID] [nvarchar](100) NULL,\r\n\t[GF_Ticket_Number] [nvarchar](50) NULL,\r\n\t[SubmissionDate] [datetime] NULL,\r\n\t[GPS_Location] [nvarchar](100) NULL,\r\n\t[Job_Selection_Raw] [nvarchar](255) NULL,\r\n\t[Origin_Dest_Type_Raw] [nvarchar](50) NULL,\r\n\t[Origin_Dest_Specific_Job] [nvarchar](255) NULL,\r\n\t[Origin_Dest_Specific_Disposal] [nvarchar](255) NULL,\r\n\t[Origin_Dest_Specific_Other] [nvarchar](255) NULL,\r\n\t[Flow_Direction_Raw] [nvarchar](50) NULL,\r\n\t[Raw_Import_Category] [nvarchar](100) NULL,\r\n\t[Raw_Backfill_Select] [nvarchar](100) NULL,\r\n\t[Raw_Delivery_Select] [nvarchar](100) NULL,\r\n\t[Other_Import] [nvarchar](100) NULL,\r\n\t[Raw_Agg_Category] [nvarchar](100) NULL,\r\n\t[Raw_Agg_Gravel] [nvarchar](100) NULL,\r\n\t[Raw_Agg_Recycled] [nvarchar](100) NULL,\r\n\t[Raw_Agg_CrushedRun] [nvarchar](100) NULL,\r\n\t[Raw_Agg_LargeStone] [nvarchar](100) NULL,\r\n\t[Raw_Masonry_Category] [nvarchar](100) NULL,\r\n\t[Raw_Masonry_Sand] [nvarchar](100) NULL,\r\n\t[Raw_Masonry_Mat] [nvarchar](100) NULL,\r\n\t[Raw_Export_Category] [nvarchar](100) NULL,\r\n\t[Other_Export] [nvarchar](100) NULL,\r\n\t[Raw_Scrap_Category] [nvarchar](100) NULL,\r\n\t[Raw_Scrap_Ferrous] [nvarchar](100) NULL,\r\n\t[Raw_Scrap_NonFerrous] [nvarchar](100) NULL,\r\n\t[Raw_Scrap_AlumWire] [nvarchar](100) NULL,\r\n\t[Raw_Scrap_CuTubing] [nvarchar](100) NULL,\r\n\t[Raw_Scrap_CuWire] [nvarchar](100) NULL,\r\n\t[Raw_Asbestos_Type] [nvarchar](100) NULL,\r\n\t[Hauler] [nvarchar](50) NULL,\r\n\t[Raw_Co_Other] [nvarchar](100) NULL,\r\n\t[Truck_Type_Raw] [nvarchar](100) NULL,\r\n\t[Roll_Off_Truck_Type] [nvarchar](10) NULL,\r\n\t[Raw_Driver_Select] [nvarchar](100) NULL,\r\n\t[Raw_Driver_Manual] [nvarchar](100) NULL,\r\n\t[Raw_Driver_Phone] [nvarchar](100) NULL,\r\n\t[Raw_Driver_Email] [nvarchar](100) NULL,\r\n\t[Has_Ticket_Bool] [nvarchar](50) NULL,\r\n\t[Physical_Ticket_Raw] [nvarchar](100) NULL,\r\n\t[Signed_By_Select] [nvarchar](100) NULL,\r\n\t[Signed_By_Manual] [nvarchar](100) NULL,\r\n\t[Link_Pic_Ticket] [nvarchar](max) NULL,\r\n\t[Link_Pic_Truck1] [nvarchar](max) NULL,\r\n\t[Link_Pic_Truck2] [nvarchar](max) NULL,\r\n\t[Link_Pic_Scrap] [nvarchar](max) NULL,\r\n\t[Link_Pic_Asbestos] [nvarchar](max) NULL,\r\n\t[ProcessedDate] [datetime] NULL,\r\n\t[TruckNumber] [nvarchar](50) NULL,\r\n\t[Existing_Signer_Tel_number] [varchar](50) NULL,\r\n\t[New_Signer_Tel_number] [varchar](50) NULL,\r\n CONSTRAINT [PK__Stage_Si__03EB7AF8529F7380] PRIMARY KEY CLUSTERED \r\n(\r\n\t[StageID] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY] TEXTIMAGE_ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Stage_SiteTickets' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [dbo].[VW_SiteTickets_Excel_Report]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/View[@Name='VW_SiteTickets_Excel_Report' and @Schema='dbo']","object_type":"View"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  View [dbo].[VW_SiteTickets_Excel_Report]    Script Date: 3/17/2026 1:39:56 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE VIEW [dbo].[VW_SiteTickets_Excel_Report]\r\nAS\r\nSELECT \r\n    -- Ticket Info\r\n    F.TicketID,\r\n    F.TicketDate,\r\n    F.FormTicketNumber,\r\n    F.TruckNumber,\r\n    \r\n    -- === THE FIX ===\r\n    -- JOB: Try Ref table first, otherwise grab raw from Stage\r\n    COALESCE(J.JobName, Stg.Job_Selection_Raw) AS JobName,\r\n\r\n    -- SITE: Try Ref table first, otherwise grab raw from Stage\r\n    COALESCE(S.SiteName, COALESCE(Stg.Origin_Dest_Specific_Disposal, Stg.Origin_Dest_Specific_Job, Stg.Origin_Dest_Specific_Other)) AS SiteName,\r\n\r\n    -- COMPANY: Try Ref table first, otherwise grab the first non-null Raw Company field\r\n    COALESCE(C.CompanyName, COALESCE(Stg.Raw_Co_RollOff, Stg.Raw_Co_Dump, Stg.Raw_Co_Walking, Stg.Raw_Co_EndDump, Stg.Raw_Co_Other)) AS [Trucking Company],\r\n\r\n    -- TRUCK TYPE: Try Ref table first, otherwise grab Raw\r\n    COALESCE(T.TypeName, Stg.Truck_Type_Raw) AS [Truck Type],\r\n    \r\n    -- MATERIAL: Try Ref table first, otherwise grab Raw (complex coalesce)\r\n    COALESCE(M.MaterialName, COALESCE(\r\n                Stg.Raw_Agg_Gravel, Stg.Raw_Agg_Recycled, Stg.Raw_Agg_CrushedRun, Stg.Raw_Agg_LargeStone, \r\n                Stg.Raw_Masonry_Sand, Stg.Raw_Masonry_Mat, \r\n                Stg.Raw_Scrap_Ferrous, Stg.Raw_Scrap_NonFerrous, Stg.Raw_Scrap_AlumWire, Stg.Raw_Scrap_CuTubing, Stg.Raw_Scrap_CuWire,\r\n                Stg.Raw_Asbestos_Type, Stg.Raw_Import_Category, Stg.Raw_Export_Category\r\n            )) AS [Material],\r\n\r\n    -- DRIVER: Try Ref table first, otherwise Raw\r\n    COALESCE(D.DriverName, COALESCE(Stg.Raw_Driver_Manual, Stg.Raw_Driver_Select)) AS DriverName,\r\n    \r\n    -- Other Info\r\n    F.Direction,\r\n    F.HasPhysicalTicket,\r\n    F.PhysicalTicketNumber,\r\n    F.SignedBy,\r\n    F.CreatedAt\r\n    \r\nFROM Fact_SiteTickets F\r\n-- Join the Stage table to get the raw text backup\r\nLEFT JOIN Stage_SiteTickets Stg ON F.FormTicketNumber = Stg.GF_Ticket_Number\r\n\r\n-- Join Reference Tables (Normal method)\r\nLEFT JOIN Ref_Jobs J ON F.JobID = J.JobID\r\nLEFT JOIN Ref_ExternalSites S ON F.ExternalSiteID = S.SiteID\r\nLEFT JOIN Ref_ExternalCompanies C ON F.TruckingCompanyID = C.CompanyID\r\nLEFT JOIN Ref_TruckTypes T ON F.TruckTypeID = T.TruckTypeID\r\nLEFT JOIN Ref_Materials M ON F.MaterialID = M.MaterialID\r\nLEFT JOIN Ref_Drivers D ON F.DriverID = D.DriverID;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/View[@Name='VW_SiteTickets_Excel_Report' and @Schema='dbo']","object_type":"View"}},{"cell_type":"markdown","source":["# [dbo].[Fact_TicketPhotos]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Fact_TicketPhotos' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  Table [dbo].[Fact_TicketPhotos]    Script Date: 3/17/2026 1:39:56 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE TABLE [dbo].[Fact_TicketPhotos](\r\n\t[PhotoID] [int] IDENTITY(1,1) NOT NULL,\r\n\t[TicketID] [int] NOT NULL,\r\n\t[PhotoType] [nvarchar](50) NULL,\r\n\t[PhotoURL] [nvarchar](max) NULL,\r\n\t[UploadedAt] [datetime] NULL,\r\nPRIMARY KEY CLUSTERED \r\n(\r\n\t[PhotoID] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY] TEXTIMAGE_ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Fact_TicketPhotos' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [dbo].[Ref_CompanyContacts]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_CompanyContacts' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  Table [dbo].[Ref_CompanyContacts]    Script Date: 3/17/2026 1:39:56 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE TABLE [dbo].[Ref_CompanyContacts](\r\n\t[ContactID] [int] IDENTITY(1,1) NOT NULL,\r\n\t[CompanyID] [int] NOT NULL,\r\n\t[ContactName] [nvarchar](100) NULL,\r\n\t[Role] [nvarchar](50) NULL,\r\n\t[Phone] [nvarchar](50) NULL,\r\n\t[Email] [nvarchar](100) NULL,\r\nPRIMARY KEY CLUSTERED \r\n(\r\n\t[ContactID] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_CompanyContacts' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [dbo].[Ref_DisposalRates]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_DisposalRates' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count