erver[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_Jobs' and @Schema='dbo']/ForeignKey[@Name='FK_Jobs_Entity']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Ref_Jobs]  WITH CHECK ADD  CONSTRAINT [FK_Jobs_Entity] FOREIGN KEY([EntityID])\r\nREFERENCES [dbo].[Ref_OurEntities] ([EntityID])\r\n","GO\r\n","ALTER TABLE [dbo].[Ref_Jobs] CHECK CONSTRAINT [FK_Jobs_Entity]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_Jobs' and @Schema='dbo']/ForeignKey[@Name='FK_Jobs_Entity']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK_Materials_Parent]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_Materials' and @Schema='dbo']/ForeignKey[@Name='FK_Materials_Parent']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Ref_Materials]  WITH CHECK ADD  CONSTRAINT [FK_Materials_Parent] FOREIGN KEY([ParentMaterialID])\r\nREFERENCES [dbo].[Ref_Materials] ([MaterialID])\r\n","GO\r\n","ALTER TABLE [dbo].[Ref_Materials] CHECK CONSTRAINT [FK_Materials_Parent]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_Materials' and @Schema='dbo']/ForeignKey[@Name='FK_Materials_Parent']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK_Rates_Company]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_TruckingRates' and @Schema='dbo']/ForeignKey[@Name='FK_Rates_Company']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Ref_TruckingRates]  WITH CHECK ADD  CONSTRAINT [FK_Rates_Company] FOREIGN KEY([CompanyID])\r\nREFERENCES [dbo].[Ref_ExternalCompanies] ([CompanyID])\r\n","GO\r\n","ALTER TABLE [dbo].[Ref_TruckingRates] CHECK CONSTRAINT [FK_Rates_Company]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_TruckingRates' and @Schema='dbo']/ForeignKey[@Name='FK_Rates_Company']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK_Rates_TruckType]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_TruckingRates' and @Schema='dbo']/ForeignKey[@Name='FK_Rates_TruckType']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Ref_TruckingRates]  WITH CHECK ADD  CONSTRAINT [FK_Rates_TruckType] FOREIGN KEY([TruckTypeID])\r\nREFERENCES [dbo].[Ref_TruckTypes] ([TruckTypeID])\r\n","GO\r\n","ALTER TABLE [dbo].[Ref_TruckingRates] CHECK CONSTRAINT [FK_Rates_TruckType]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/Table[@Name='Ref_TruckingRates' and @Schema='dbo']/ForeignKey[@Name='FK_Rates_TruckType']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [dbo].[USP_Process_GoFormz_Tickets]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/StoredProcedure[@Name='USP_Process_GoFormz_Tickets' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[USP_Process_GoFormz_Tickets]    Script Date: 3/17/2026 1:39:56 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[USP_Process_GoFormz_Tickets]\r\nAS\r\nBEGIN\r\n    SET NOCOUNT ON;\r\n\r\n    -- 1. Identify new tickets\r\n    DECLARE @NewTickets TABLE (StageID INT);\r\n    INSERT INTO @NewTickets\r\n    SELECT StageID FROM Stage_SiteTickets WHERE ProcessedDate IS NULL;\r\n\r\n    DECLARE @CurrentStageID INT;\r\n\r\n    -- Variables\r\n    DECLARE @GoFormzID NVARCHAR(100), @FormAutoNum NVARCHAR(50);\r\n    DECLARE @TicketDate DATETIME, @JobName NVARCHAR(255);\r\n    DECLARE @Direction NVARCHAR(50), @SiteName NVARCHAR(255);\r\n    DECLARE @TruckType NVARCHAR(100), @RawMaterial NVARCHAR(100), @RawCompany NVARCHAR(100);\r\n    DECLARE @TruckNumber NVARCHAR(50); \r\n    \r\n    DECLARE @DriverName NVARCHAR(100), @DriverPhone NVARCHAR(100), @DriverEmail NVARCHAR(100);\r\n    DECLARE @HasPhysicalTicket NVARCHAR(50), @PhysicalTicketNum NVARCHAR(100), @SignedBy NVARCHAR(100);\r\n    DECLARE @JobID INT, @MaterialID INT, @CompanyID INT, @SiteID INT, @TruckTypeID INT, @DriverID INT;\r\n    DECLARE @NewTicketID INT;\r\n\r\n    DECLARE ticket_cursor CURSOR FOR SELECT StageID FROM @NewTickets;\r\n    OPEN ticket_cursor;\r\n    FETCH NEXT FROM ticket_cursor INTO @CurrentStageID;\r\n\r\n    WHILE @@FETCH_STATUS = 0\r\n    BEGIN\r\n        -- A. READ RAW DATA\r\n        SELECT \r\n            @GoFormzID = GoFormz_ID,\r\n            @FormAutoNum = GF_Ticket_Number,\r\n            @TicketDate = SubmissionDate,\r\n            @TruckNumber = TruckNumber,\r\n            @JobName = Job_Selection_Raw,\r\n            @Direction = Flow_Direction_Raw,\r\n            @SiteName = COALESCE(Origin_Dest_Specific_Disposal, Origin_Dest_Specific_Job, Origin_Dest_Specific_Other),\r\n            \r\n            -- REMOVED: Raw_Co_RollOff, Raw_Co_Dump, Raw_Co_Walking, Raw_Co_EndDump\r\n            -- These were causing Error 207 because they do not exist in the [Stage_SiteTickets] table.\r\n            @RawCompany = COALESCE(Raw_Co_Other, Hauler), \r\n\r\n            @RawMaterial = COALESCE(\r\n                Raw_Agg_Gravel, Raw_Agg_Recycled, Raw_Agg_CrushedRun, Raw_Agg_LargeStone, \r\n                Raw_Masonry_Sand, Raw_Masonry_Mat, \r\n                Raw_Scrap_Ferrous, Raw_Scrap_NonFerrous, Raw_Scrap_AlumWire, Raw_Scrap_CuTubing, Raw_Scrap_CuWire,\r\n                Raw_Asbestos_Type, Raw_Import_Category, Raw_Export_Category\r\n            ),\r\n            @TruckType = Truck_Type_Raw,\r\n            @DriverName = COALESCE(Raw_Driver_Manual, Raw_Driver_Select),\r\n            @DriverPhone = Raw_Driver_Phone,\r\n            @DriverEmail = Raw_Driver_Email,\r\n            @HasPhysicalTicket = Has_Ticket_Bool,\r\n            @PhysicalTicketNum = Physical_Ticket_Raw,\r\n            @SignedBy = COALESCE(Signed_By_Manual, Signed_By_Select)\r\n        FROM Stage_SiteTickets WHERE StageID = @CurrentStageID;\r\n\r\n        -- B. RESOLVE LOOKUP IDs\r\n        SELECT @JobID = JobID FROM Ref_Jobs WHERE JobName = @JobName OR JobNumber = @JobName;\r\n        SELECT @MaterialID = MaterialID FROM Ref_Materials WHERE MaterialName = @RawMaterial;\r\n        SELECT @CompanyID = CompanyID FROM Ref_ExternalCompanies WHERE CompanyName = @RawCompany;\r\n        SELECT @SiteID = SiteID FROM Ref_ExternalSites WHERE SiteName = @SiteName;\r\n        SELECT @TruckTypeID = TruckTypeID FROM Ref_TruckTypes WHERE TypeName = @TruckType;\r\n\r\n        -- Auto-create Driver\r\n        IF @DriverName IS NOT NULL\r\n        BEGIN\r\n            SELECT @DriverID = DriverID FROM Ref_Drivers WHERE DriverName = @DriverName;\r\n            IF @DriverID IS NULL\r\n            BEGIN\r\n                INSERT INTO Ref_Drivers (DriverName, Phone, Email) VALUES (@DriverName, @DriverPhone, @DriverEmail);\r\n                SET @DriverID = SCOPE_IDENTITY();\r\n            END\r\n        END\r\n\r\n        -- C. INSERT INTO PRODUCTION\r\n        IF @JobID IS NOT NULL AND @MaterialID IS NOT NULL AND @FormAutoNum IS NOT NULL\r\n        BEGIN\r\n            IF NOT EXISTS (SELECT 1 FROM Fact_SiteTickets WHERE FormTicketNumber = @FormAutoNum)\r\n            BEGIN\r\n                INSERT INTO Fact_SiteTickets (\r\n                    GoFormzID, FormTicketNumber, TicketDate, JobID, ExternalSiteID, \r\n                    TruckingCompanyID, TruckTypeID, DriverID, MaterialID, Direction, \r\n                    TruckNumber,\r\n                    HasPhysicalTicket, PhysicalTicketNumber, SignedBy\r\n                )\r\n                VALUES (\r\n                    @GoFormzID, @FormAutoNum, @TicketDate, @JobID, @SiteID, \r\n                    @CompanyID, @TruckTypeID, @DriverID, @MaterialID, LEFT(@Direction, 10), \r\n                    @TruckNumber,\r\n                    CASE WHEN @HasPhysicalTicket IN ('Yes', 'True', '1') THEN 1 ELSE 0 END, \r\n                    @PhysicalTicketNum, @SignedBy\r\n                );\r\n\r\n                SET @NewTicketID = SCOPE_IDENTITY();\r\n\r\n                -- D. HANDLE PHOTOS\r\n                INSERT INTO Fact_TicketPhotos (TicketID, PhotoType, PhotoURL)\r\n                SELECT @NewTicketID, 'Ticket', Link_Pic_Ticket FROM Stage_SiteTickets WHERE StageID = @CurrentStageID AND Link_Pic_Ticket IS NOT NULL;\r\n                INSERT INTO Fact_TicketPhotos (TicketID, PhotoType, PhotoURL)\r\n                SELECT @NewTicketID, 'Rear', Link_Pic_Truck1 FROM Stage_SiteTickets WHERE StageID = @CurrentStageID AND Link_Pic_Truck1 IS NOT NULL;\r\n                INSERT INTO Fact_TicketPhotos (TicketID, PhotoType, PhotoURL)\r\n                SELECT @NewTicketID, 'Side', Link_Pic_Truck2 FROM Stage_SiteTickets WHERE StageID = @CurrentStageID AND Link_Pic_Truck2 IS NOT NULL;\r\n                INSERT INTO Fact_TicketPhotos (TicketID, PhotoType, PhotoURL)\r\n                SELECT @NewTicketID, 'Scrap', Link_Pic_Scrap FROM Stage_SiteTickets WHERE StageID = @CurrentStageID AND Link_Pic_Scrap IS NOT NULL;\r\n                INSERT INTO Fact_TicketPhotos (TicketID, PhotoType, PhotoURL)\r\n                SELECT @NewTicketID, 'Asbestos', Link_Pic_Asbestos FROM Stage_SiteTickets WHERE StageID = @CurrentStageID AND Link_Pic_Asbestos IS NOT NULL;\r\n            END\r\n            \r\n            -- E. MARK COMPLETE\r\n            UPDATE Stage_SiteTickets SET ProcessedDate = GETDATE() WHERE StageID = @CurrentStageID;\r\n        END\r\n\r\n        FETCH NEXT FROM ticket_cursor INTO @CurrentStageID;\r\n    END\r\n\r\n    CLOSE ticket_cursor;\r\n    DEALLOCATE ticket_cursor;\r\nEND\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']/StoredProcedure[@Name='USP_Process_GoFormz_Tickets' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [GoFormzDB]"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']","object_type":"Database"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["USE [master]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']","object_type":"Database"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER DATABASE [GoFormzDB] SET  READ_WRITE \r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-ABGH50D\\SQLEXPRESS']/Database[@Name='GoFormzDB']","object_type":"Database"}}]}